class OrderBuilder:
    def __init__(self):
        self._data = {"status": "pending", "items": [], "discount": 0}

    def with_item(self, product_id: int, qty: int = 1) -> "OrderBuilder":
        self._data["items"].append({"product_id": product_id, "qty": qty})
        return self

    def with_discount(self, percent: int) -> "OrderBuilder":
        self._data["discount"] = percent
        return self

    def build(self) -> dict:
        return {**self._data}

# Usage:
order = OrderBuilder().with_item(1).with_item(2, qty=3).with_discount(10).build()

class UserMother:
    @staticmethod
    def premium_user() -> User:
        return UserFactory(role="premium", subscription_active=True)

    @staticmethod
    def banned_user() -> User:
        return UserFactory(is_banned=True, ban_reason="policy violation")

    @staticmethod
    def new_user_without_profile() -> User:
        return UserFactory(profile=None)

# Usage makes test intent clear:
def test_premium_features_accessible():
    user = UserMother.premium_user()
    assert user.can_access_premium_features()
